package br.com.portfolio.ecommerce.order.api;
import br.com.portfolio.ecommerce.order.application.port.in.*; import br.com.portfolio.ecommerce.order.domain.Order; import jakarta.validation.Valid; import jakarta.validation.constraints.*; import org.springframework.http.ResponseEntity; import org.springframework.web.bind.annotation.*; import java.math.BigDecimal; import java.util.*;
@RestController @RequestMapping("/api/v1/orders") public class OrderController { private final CheckoutUseCase checkout; public OrderController(CheckoutUseCase checkout){this.checkout=checkout;} @PostMapping("/checkout") ResponseEntity<OrderResponse> checkout(@RequestHeader("Idempotency-Key") String idempotencyKey,@Valid @RequestBody CheckoutRequest r){ var cmd=new CheckoutCommand(r.customerId(),r.couponCode(),r.shippingZipCode(),r.items().stream().map(i->new CheckoutCommand.Item(i.productId(),i.quantity())).toList(),idempotencyKey); return ResponseEntity.ok(OrderResponse.from(checkout.checkout(cmd))); } public record CheckoutRequest(@NotNull UUID customerId,String couponCode,@NotBlank String shippingZipCode,@NotEmpty List<ItemRequest> items){} public record ItemRequest(@NotNull UUID productId,@Min(1) int quantity){} public record OrderResponse(UUID id,UUID customerId,String status,BigDecimal subtotal,BigDecimal discount,BigDecimal shipping,BigDecimal total){ static OrderResponse from(Order o){ return new OrderResponse(o.id(),o.customerId(),o.status().name(),o.subtotal().amount(),o.discount().amount(),o.shipping().amount(),o.total().amount()); } } }
